package app

import (
	"fmt"
	"log"

	"pharma-platform/backend/internal/config"
	"pharma-platform/backend/internal/database"
	"pharma-platform/backend/internal/router"
)

func Run() error {
	cfg, err := config.Load()
	if err != nil {
		return fmt.Errorf("load config: %w", err)
	}

	db, err := database.NewMySQL(cfg)
	if err != nil {
		return fmt.Errorf("connect database: %w", err)
	}
	defer db.Close()

	r := router.New(cfg, db)
	addr := fmt.Sprintf(":%d", cfg.AppPort)

	log.Printf("backend listening on %s", addr)
	return r.Run(addr)
}
EOF

cat > backend/internal/config/config.go <<'EOF'
package config

import (
	"fmt"
	"os"
	"strconv"
)

type Config struct {
	AppEnv      string
	AppPort     int
	DBHost      string
	DBPort      int
	DBName      string
	DBUser      string
	DBPassword  string
	JWTSecret   string
	JWTExpHours int
}

func Load() (Config, error) {
	cfg := Config{
		AppEnv:      getEnv("APP_ENV", "development"),
		AppPort:     getEnvInt("APP_PORT", 8080),
		DBHost:      getEnv("DB_HOST", "mysql"),
		DBPort:      getEnvInt("DB_PORT", 3306),
		DBName:      getEnv("DB_NAME", "pharma_platform"),
		DBUser:      getEnv("DB_USER", "pharma_user"),
		DBPassword:  getEnv("DB_PASSWORD", "pharma_pass"),
		JWTSecret:   getEnv("JWT_SECRET", "change_me_for_dev_only"),
		JWTExpHours: getEnvInt("JWT_EXP_HOURS", 8),
	}

	if cfg.JWTExpHours <= 0 {
		return Config{}, fmt.Errorf("JWT_EXP_HOURS must be greater than 0")
	}

	return cfg, nil
}

func getEnv(key, fallback string) string {
	if value, ok := os.LookupEnv(key); ok && value != "" {
		return value
	}
	return fallback
}

func getEnvInt(key string, fallback int) int {
	value := os.Getenv(key)
	if value == "" {
		return fallback
	}
	parsed, err := strconv.Atoi(value)
	if err != nil {
		return fallback
	}
	return parsed
}
EOF

cat > backend/internal/database/mysql.go <<'EOF'
package database

import (
	"database/sql"
	"fmt"
	"time"

	_ "github.com/go-sql-driver/mysql"

	"pharma-platform/backend/internal/config"
)

func NewMySQL(cfg config.Config) (*sql.DB, error) {
	dsn := fmt.Sprintf(
		"%s:%s@tcp(%s:%d)/%s?parseTime=true&charset=utf8mb4&loc=UTC",
		cfg.DBUser,
		cfg.DBPassword,
		cfg.DBHost,
		cfg.DBPort,
		cfg.DBName,
	)

	db, err := sql.Open("mysql", dsn)
	if err != nil {
		return nil, fmt.Errorf("open mysql: %w", err)
	}

	db.SetMaxOpenConns(20)
	db.SetMaxIdleConns(10)
	db.SetConnMaxLifetime(5 * time.Minute)

	var pingErr error
	for range 20 {
		pingErr = db.Ping()
		if pingErr == nil {
			return db, nil
		}
		time.Sleep(2 * time.Second)
	}

	_ = db.Close()
	return nil, fmt.Errorf("ping mysql after retries: %w", pingErr)
}
EOF

cat > backend/internal/handler/health.go <<'EOF'
package handler

import (
	"database/sql"
	"net/http"
	"time"

	"github.com/gin-gonic/gin"
)

type HealthHandler struct {
	db *sql.DB
}

func NewHealthHandler(db *sql.DB) HealthHandler {
	return HealthHandler{db: db}
}

func (h HealthHandler) GetHealth(c *gin.Context) {
	dbStatus := "up"
	status := "ok"

	if err := h.db.Ping(); err != nil {
		dbStatus = "down"
		status = "degraded"
	}

	c.JSON(http.StatusOK, gin.H{
		"status":   status,
		"database": dbStatus,
		"service":  "go-backend",
		"time":     time.Now().UTC().Format(time.RFC3339),
	})
}
EOF

cat > backend/internal/router/router.go <<'EOF'
package router

import (
	"database/sql"

	"github.com/gin-gonic/gin"

	"pharma-platform/backend/internal/config"
	"pharma-platform/backend/internal/handler"
)

func New(cfg config.Config, db *sql.DB) *gin.Engine {
	if cfg.AppEnv == "production" {
		gin.SetMode(gin.ReleaseMode)
	}

	r := gin.Default()

	healthHandler := handler.NewHealthHandler(db)

	api := r.Group("/api/v1")
	{
		api.GET("/health", healthHandler.GetHealth)
	}

	return r
}
