		&user.FullName,
		&passwordHash,
		&user.Role,
		&user.ScopeID,
		&user.Institution,
		&user.Department,
		&user.Team,
	); err != nil {
		writeError(c, http.StatusUnauthorized, "INVALID_CREDENTIALS", "invalid username or password")
		return
	}

	if bcrypt.CompareHashAndPassword([]byte(passwordHash), []byte(req.Password)) != nil {
