		FROM audit_logs
		WHERE `+strings.Join(whereParts, " AND ")+`
		ORDER BY id DESC
		LIMIT 20000
	`, args...)
	if err != nil {
		writeError(c, http.StatusInternalServerError, "DB_ERROR", "failed to export audit logs")
		return
	}
	defer rows.Close()

